{
  "name": "MecanoLink B2B Marketplace",
  "description": "A specialized B2B marketplace for automotive workshops to outsource complex services to specialists, featuring AI diagnostics, reputation systems, and automated commission management.",
  "requestFramePermissions": [
    "camera",
    "geolocation"
  ]
}

export enum UserRole {
  DERIVADOR = 'DERIVADOR',
  ESPECIALISTA = 'ESPECIALISTA'
}

export enum Specialty {
  HYBRID = 'Híbridos y Eléctricos',
  DIESEL = 'Inyección Diésel',
  TRANSMISSION = 'Transmisiones CVT/AT',
  ELECTRONICS = 'Electrónica Avanzada',
  ADAS = 'Sistemas ADAS',
  BODYWORK = 'Carrocería Especializada'
}

export enum JobStatus {
  PENDING = 'Pendiente',
  QUOTED = 'Cotizado',
  IN_PROGRESS = 'En Proceso',
  COMPLETED = 'Completado',
  PAID = 'Pagado'
}

export interface Workshop {
  id: string;
  name: string;
  specialties: Specialty[];
  rating: number;
  location: { lat: number; lng: number; address: string };
  image: string;
  certifications: string[];
  responseTime: string;
  verified: boolean;
}

export interface JobRequest {
  id: string;
  vehicle: string;
  issue: string;
  codes: string;
  status: JobStatus;
  urgency: 'Baja' | 'Media' | 'Alta';
  derivadorId: string;
  especialistaId?: string;
  price?: number;
  commission?: number;
  createdAt: string;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAIDiagnosticSuggestion = async (issue: string, codes: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Eres un asistente experto para talleres mecánicos. Analiza el siguiente problema y códigos OBD2: 
      Problema: ${issue}
      Códigos: ${codes}

      Proporciona:
      1. Un diagnóstico preliminar.
      2. El tipo de especialista recomendado.
      3. Una estimación de costo (rango en Euros).
      4. Nivel de complejidad (1-10).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            diagnosis: { type: Type.STRING },
            specialtyType: { type: Type.STRING },
            estimatedCost: { type: Type.STRING },
            complexity: { type: Type.NUMBER }
          },
          required: ["diagnosis", "specialtyType", "estimatedCost", "complexity"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("AI Diagnostic Error:", error);
    return null;
  }
};

