import { GoogleGenAI, Type } from "@google/genai";

export const getAIDiagnosticSuggestion = async (issue: string, codes: string) => {
  if (!process.env.API_KEY) {
    console.error("API_KEY no configurada");
    return null;
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analiza este caso técnico automotriz y responde estrictamente en JSON.
      Problema: ${issue}
      Códigos: ${codes}

      Esquema requerido:
      {
        "diagnosis": "string",
        "specialtyType": "string",
        "estimatedCost": "string",
        "complexity": number (1-10)
      }`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            diagnosis: { type: Type.STRING },
            specialtyType: { type: Type.STRING },
            estimatedCost: { type: Type.STRING },
            complexity: { type: Type.NUMBER }
          },
          required: ["diagnosis", "specialtyType", "estimatedCost", "complexity"]
        }
      }
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text);
  } catch (error) {
    console.error("AI Diagnostic Error:", error);
    return {
      diagnosis: "Error al procesar el diagnóstico con IA.",
      specialtyType: "General",
      estimatedCost: "N/A",
      complexity: 5
    };
  }
};

