  const [formData, setFormData] = useState({
    name: '',
    taxId: '',
    phone: '',
    address: '',
    specialty: Specialty.ELECTRONICS
  });

  const handleVerify = (id: string) => {
    setWorkshops(workshops.map(w => w.id === id ? { ...w, verified: !w.verified } : w));
  };

  const openEdit = (workshop: Workshop) => {
    setEditingWorkshop(workshop);
    setFormData({
      name: workshop.name,
      taxId: `B-${workshop.id}66281`, // Simulando dato fiscal
      phone: '+34 600 000 000',
      address: workshop.location.address,
      specialty: workshop.specialties[0]
    });
    setShowEditModal(true);
  };

  const saveEdit = () => {
    if (editingWorkshop) {
      setWorkshops(workshops.map(w => 
        w.id === editingWorkshop.id 
          ? { ...w, name: formData.name, specialties: [formData.specialty], location: { ...w.location, address: formData.address } }
