import React, { useState } from 'react';
import { UserRole } from './types';
import Layout from './components/Layout';
import DashboardDerivador from './components/DashboardDerivador';
import DashboardEspecialista from './components/DashboardEspecialista';
import AdminPanel from './components/AdminPanel';
import Auth from './components/Auth';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');

  const handleLogin = (selectedRole: UserRole) => {
    setRole(selectedRole);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setRole(null);
    setActiveTab('dashboard');
  };

  if (!role) {
    return <Auth onLogin={handleLogin} />;
  }

  const renderContent = () => {
    // El Administrador siempre usa el AdminPanel, pero le pasamos el activeTab 
    // para que el propio componente decida qué submódulo mostrar (Usuarios, Auditoría, Finanzas)
    if (role === UserRole.ADMIN) {
      return <AdminPanel activeTab={activeTab} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return role === UserRole.DERIVADOR ? <DashboardDerivador /> : <DashboardEspecialista />;
      case 'messages':
        return (
          <div className="bg-white rounded-[3rem] border-2 border-slate-100 h-[70vh] flex flex-col items-center justify-center p-8 text-center shadow-sm animate-in fade-in duration-500">
            <div className="w-24 h-24 bg-slate-900 rounded-full flex items-center justify-center text-brand mb-6 shadow-xl">
              <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"/></svg>
