import { GoogleGenAI, Type } from "@google/genai";

/**
 * Gets a diagnostic suggestion from Gemini based on issue description and DTC codes.
 */
export const getAIDiagnosticSuggestion = async (issue: string, codes: string) => {
  // Acceso directo a la clave de entorno según las instrucciones
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    throw new Error("API_KEY no configurada en el entorno");
  }

  // Inicialización correcta con objeto de parámetros
  const ai = new GoogleGenAI({ apiKey });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", // Usando flash para mayor velocidad en diagnósticos rápidos
      contents: `Eres un experto maestro mecánico B2B. Analiza el siguiente problema técnico y responde EXCLUSIVAMENTE en formato JSON.

      DATOS DEL VEHÍCULO Y FALLO:
      Problema reportado: ${issue}
      Códigos DTC: ${codes || 'No proporcionados'}

      ESQUEMA JSON DE RESPUESTA:
      {
        "diagnosis": "Explicación técnica concisa de la posible avería",
        "specialtyType": "Nombre de la especialidad necesaria (ej: Electrónica, Transmisiones, etc.)",
        "estimatedCost": "Rango de precio estimado en Euros (ej: 200€ - 450€)",
        "complexity": "Número del 1 al 10"
      }`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            diagnosis: { type: Type.STRING },
            specialtyType: { type: Type.STRING },
            estimatedCost: { type: Type.STRING },
            complexity: { type: Type.STRING }
          },
          required: ["diagnosis", "specialtyType", "estimatedCost", "complexity"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Respuesta vacía de la IA");

    return JSON.parse(text.trim());
  } catch (error) {
    console.error("AI Diagnostic Error:", error);
    throw error;
  }
};

