                        <div className="bg-slate-800 p-4 rounded-2xl">
                          <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest block mb-1">Presupuesto Est.</span>
                          <p className="text-white font-black text-xs">{aiResult.estimatedCost}</p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>

                <div className="flex gap-4 pt-4">
                  <button onClick={() => setShowForm(false)} className="flex-1 py-5 rounded-[1.5rem] bg-slate-50 text-slate-400 font-black text-xs uppercase tracking-widest transition hover:bg-slate-100">Cancelar</button>
                  <button 
                    onClick={handlePublish}
                    disabled={isPublishing}
                    className={`flex-1 py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-widest shadow-xl transition-all ${isPublishing ? 'bg-slate-800 text-slate-500' : 'bg-slate-950 text-brand hover:scale-[1.02]'}`}
                  >
                    {isPublishing ? 'Distribuyendo...' : 'Publicar en Red'}
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

