  // Estado para el formulario
  const [vehicle, setVehicle] = useState('');
  const [issue, setIssue] = useState('');
  const [codes, setCodes] = useState('');
  const [urgency, setUrgency] = useState<'Baja' | 'Media' | 'Alta'>('Media');

  // Estado de la IA y publicación
  const [aiLoading, setAiLoading] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [aiResult, setAiResult] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);

  // Lista dinámica de trabajos
  const [myJobs, setMyJobs] = useState<Partial<JobRequest>[]>([
    { id: '1', vehicle: 'Toyota Prius 2018', status: JobStatus.IN_PROGRESS, issue: 'Fallo batería híbrida', createdAt: new Date().toISOString() },
    { id: '2', vehicle: 'BMW X5 Diesel', status: JobStatus.QUOTED, issue: 'Limpieza DPF', createdAt: new Date().toISOString() },
  ]);

