import React, { useState } from 'react';
import { MOCK_WORKSHOPS } from '../constants.tsx';
import { Specialty, JobStatus, Workshop, JobRequest } from '../types';
import { getAIDiagnosticSuggestion } from '../services/geminiService';

const DashboardDerivador: React.FC = () => {
  const [search, setSearch] = useState('');
  const [selectedSpecialty, setSelectedSpecialty] = useState<string>('All');
  const [showForm, setShowForm] = useState(false);
  const [viewingWorkshop, setViewingWorkshop] = useState<Workshop | null>(null);
  const [activeChat, setActiveChat] = useState<string | null>(null);

  // Estado para el formulario
  const [vehicle, setVehicle] = useState('');
  const [issue, setIssue] = useState('');
  const [codes, setCodes] = useState('');
  const [urgency, setUrgency] = useState<'Baja' | 'Media' | 'Alta'>('Media');

  // Estado de la IA y publicación
  const [aiLoading, setAiLoading] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [aiResult, setAiResult] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);

  // Lista dinámica de trabajos
  const [myJobs, setMyJobs] = useState<Partial<JobRequest>[]>([
    { id: '1', vehicle: 'Toyota Prius 2018', status: JobStatus.IN_PROGRESS, issue: 'Fallo batería híbrida', createdAt: new Date().toISOString() },
    { id: '2', vehicle: 'BMW X5 Diesel', status: JobStatus.QUOTED, issue: 'Limpieza DPF', createdAt: new Date().toISOString() },
  ]);

  const handleAiAnalyze = async (e: React.MouseEvent) => {
    e.preventDefault();
    if (!issue) {
      alert("Por favor, describe el fallo antes de analizar.");
      return;
    }

    setAiLoading(true);
    setAiResult(null);
    setError(null);

    try {
      const result = await getAIDiagnosticSuggestion(issue, codes);
      if (result) {
        setAiResult(result);
      } else {
        setError("La IA no pudo generar un diagnóstico.");
      }
    } catch (e: any) {
      console.error("Error en handleAiAnalyze:", e);
      setError("Error de conexión con el asistente técnico.");
    } finally {
      setAiLoading(false);
    }
  };

  const handlePublish = async () => {
    if (!vehicle || !issue) {
      alert("Por favor, completa al menos el vehículo y el fallo.");
      return;
    }

    setIsPublishing(true);
    await new Promise(resolve => setTimeout(resolve, 1500));

    const newJob: Partial<JobRequest> = {
      id: Math.random().toString(36).substr(2, 9),
      vehicle,
      issue,
      codes,
      status: JobStatus.PENDING,
      urgency,
      createdAt: new Date().toISOString()
    };

    setMyJobs([newJob, ...myJobs]);
    setIsPublishing(false);
    setShowForm(false);
    setVehicle('');
    setIssue('');
    setCodes('');
    setAiResult(null);
