              <div className="mt-10 flex gap-4 shrink-0">
                <button 
                  onClick={() => { setViewingWorkshop(null); setActiveChat(viewingWorkshop.name); }}
                  className="flex-1 bg-slate-950 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition active:scale-95"
                >
