      {/* SIMULACIÓN DE CHAT ACTIVO */}
      {activeChat && (
        <div className="fixed bottom-8 right-8 w-80 md:w-96 bg-white rounded-3xl shadow-2xl border-2 border-slate-100 z-[100] animate-in slide-in-from-bottom-10 overflow-hidden">
