                    >
                      <option value="Baja">NORMAL</option>
                      <option value="Media">MEDIA</option>
                      <option value="Alta">URGENTE</option>
                    </select>
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Descripción del Problema</label>
                  <textarea 
                    rows={3} 
                    placeholder="Síntomas del fallo..." 
                    className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none focus:ring-2 focus:ring-brand font-bold text-slate-800 resize-none"
                    value={issue}
                    onChange={(e) => setIssue(e.target.value)}
                  ></textarea>
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Códigos de Error (Opcional)</label>
                  <input 
                    type="text" 
                    placeholder="P0301, P0420..." 
                    className="w-full p-4 rounded-2xl bg-slate-50 border-none outline-none focus:ring-2 focus:ring-brand font-bold text-slate-800 uppercase"
                    value={codes}
                    onChange={(e) => setCodes(e.target.value)}
                  />
                </div>

                <div className="p-8 bg-slate-950 rounded-[2.5rem] border border-brand/20 shadow-2xl relative overflow-hidden">
                  <div className="flex items-center gap-5 mb-6">
                    <div className="w-12 h-12 bg-brand rounded-2xl flex items-center justify-center text-slate-950">
                       <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
                    </div>
                    <div className="flex-1">
                      <span className="font-black text-white text-lg block leading-none uppercase tracking-tighter">Asistente IA</span>
                      <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Análisis Predictivo</span>
                    </div>
                    <button 
                      type="button"
                      onClick={handleAiAnalyze}
                      disabled={aiLoading || !issue}
                      className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${aiLoading ? 'bg-slate-800 text-slate-500' : 'bg-brand text-slate-950 hover:bg-brand-light shadow-lg shadow-brand/20'}`}
                    >
                      {aiLoading ? 'Procesando...' : 'Analizar Fallo'}
                    </button>
                  </div>

                  {error && (
                    <div className="mb-4 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-500 text-[10px] font-black uppercase tracking-widest text-center">
                      {error}
                    </div>
                  )}

                  {aiResult && (
                    <div className="bg-slate-900/50 p-6 rounded-3xl border border-slate-800 space-y-4 animate-in zoom-in-95 duration-500">
                      <div className="space-y-1">
                        <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Sugerencia Técnica</span>
                        <p className="text-white text-sm font-medium leading-relaxed">{aiResult.diagnosis}</p>
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                        <div className="bg-slate-800 p-4 rounded-2xl">
                          <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest block mb-1">Especialidad</span>
                          <p className="text-brand font-black text-xs uppercase">{aiResult.specialtyType}</p>
                        </div>
                        <div className="bg-slate-800 p-4 rounded-2xl">
                          <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest block mb-1">Presupuesto Est.</span>
                          <p className="text-white font-black text-xs">{aiResult.estimatedCost}</p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>

                <div className="flex gap-4 pt-4">
                  <button onClick={() => setShowForm(false)} className="flex-1 py-5 rounded-[1.5rem] bg-slate-50 text-slate-400 font-black text-xs uppercase tracking-widest transition hover:bg-slate-100 active:scale-95">Cancelar</button>
                  <button 
                    onClick={handlePublish}
                    disabled={isPublishing}
                    className={`flex-1 py-5 rounded-[1.5rem] font-black text-xs uppercase tracking-widest shadow-xl transition-all active:scale-95 ${isPublishing ? 'bg-slate-800 text-slate-500' : 'bg-slate-950 text-brand hover:scale-[1.02]'}`}
                  >
                    {isPublishing ? 'Distribuyendo...' : 'Publicar en Red'}
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

