export enum UserRole {
  DERIVADOR = 'DERIVADOR',
  ESPECIALISTA = 'ESPECIALISTA',
  ADMIN = 'ADMIN'
}

export enum Specialty {
  HYBRID = 'Híbridos y Eléctricos',
  DIESEL = 'Inyección Diésel',
  TRANSMISSION = 'Transmisiones CVT/AT',
  ELECTRONICS = 'Electrónica Avanzada',
  ADAS = 'Sistemas ADAS',
  BODYWORK = 'Carrocería Especializada',
  MOTO_EV = 'Motos Eléctricas y Alta Gama',
  INDUSTRIAL = 'Maquinaria y Agrícola'
}

export enum JobStatus {
  PENDING = 'Pendiente',
  LOGISTICS = 'En Tránsito (Grúa)',
  QUOTED = 'Cotizado',
  IN_PROGRESS = 'En Proceso',
  VERIFYING = 'Verificando',
  COMPLETED = 'Completado',
  PAID = 'Pagado',
  WARRANTY_CLAIM = 'Reclamación Garantía'
}

export interface Workshop {
  id: string;
  name: string;
  specialties: Specialty[];
  rating: number;
  location: { lat: number; lng: number; address: string };
  image: string;
  certifications: string[];
  responseTime: string;
  verified: boolean;
  email?: string;
  capacity?: number;
}

export interface JobUpdate {
  timestamp: string;
  description: string;
  mediaUrl?: string;
  type: 'PHOTO' | 'VIDEO' | 'TEXT' | 'DIAGNOSTIC_REPORT';
}

export interface JobRequest {
  id: string;
  vehicle: string;
  vin?: string; // Bastidor para precisión técnica
  issue: string;
  codes: string;
  status: JobStatus;
  urgency: 'Baja' | 'Media' | 'Alta';
  derivadorId: string;
  especialistaId?: string;
  price?: number;
  partsIncluded: boolean; // ¿Quién pone el recambio?
  createdAt: string;
  updates?: JobUpdate[];
}

import React, { useState, useEffect } from 'react';
import { UserRole } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  role: UserRole;
  setRole: (role: UserRole) => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  onLogout?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, role, setRole, activeTab, setActiveTab, onLogout }) => {
  // Estado persistente local para saber si este usuario tiene privilegios de admin
  // aunque esté simulando otro rol
  const [hasAdminPrivileges, setHasAdminPrivileges] = useState(false);

  useEffect(() => {
    if (role === UserRole.ADMIN) {
      setHasAdminPrivileges(true);
    }
  }, [role]);

  const isAdminView = role === UserRole.ADMIN;

  const navItems = [
    { 
      id: 'dashboard', 
      label: isAdminView ? 'Red Profesional' : 'Dashboard', 
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg> 
    },
    { 
      id: 'messages', 
      label: isAdminView ? 'Auditoría Chat' : 'Mensajes', 
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"/></svg> 
    },
    { 
      id: 'commissions', 
      label: isAdminView ? 'Finanzas Red' : 'Comisiones', 
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/></svg> 
    },
  ];

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      <aside className="w-full md:w-64 bg-slate-950 text-white p-6 flex-shrink-0 flex flex-col border-r border-slate-800">
        <div className="flex items-center gap-3 mb-10">
          <div className="w-10 h-10 bg-brand rounded-xl flex items-center justify-center font-black text-xl text-slate-950 shadow-[0_0_20px_rgba(226,247,2,0.3)]">M</div>
          <h1 className="text-xl font-black tracking-tighter">MECANOLINK</h1>
        </div>

        <nav className="space-y-2 flex-1">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`flex items-center gap-3 w-full p-3 rounded-xl transition-all duration-300 ${
                activeTab === item.id 
                  ? 'bg-brand text-slate-950 font-black shadow-[0_0_15px_rgba(226,247,2,0.2)]' 
                  : 'text-slate-500 hover:bg-slate-900 hover:text-brand'
              }`}
            >
              {item.icon}
              <span className="text-sm uppercase tracking-tight">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="mt-auto pt-6 border-t border-slate-800 space-y-4">
          <button 
            onClick={onLogout}
            className="flex items-center justify-center gap-2 w-full p-3 rounded-xl border-2 border-red-500/20 text-red-500 font-black text-[10px] uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all duration-300"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"/></svg>
            Salir del Sistema
          </button>

          <p className="text-[10px] text-slate-600 uppercase font-black tracking-widest text-center">Simulación de Roles</p>
          <div className="grid grid-cols-1 gap-2">
            {/* Si tiene privilegios, mostramos siempre la opción de volver a Admin */}
            {hasAdminPrivileges && (
               <button 
                onClick={() => { setRole(UserRole.ADMIN); setActiveTab('dashboard'); }}
                className={`text-[10px] py-3 rounded-xl font-black transition-all border-2 flex items-center justify-center gap-2 ${role === UserRole.ADMIN ? 'border-blue-500 bg-blue-500/10 text-blue-400' : 'border-blue-500/30 text-blue-500/50 hover:border-blue-500 hover:text-blue-400'}`}
              >
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z"/></svg>
                PANEL ADMIN
              </button>
            )}

            <button 
              onClick={() => { setRole(UserRole.DERIVADOR); setActiveTab('dashboard'); }}
              className={`text-[10px] py-3 rounded-xl font-black transition-all border-2 ${role === UserRole.DERIVADOR ? 'border-brand bg-brand/10 text-brand' : 'border-slate-800 text-slate-500 hover:border-slate-600'}`}
            >
              TALLER GENERAL
            </button>
            <button 
              onClick={() => { setRole(UserRole.ESPECIALISTA); setActiveTab('dashboard'); }}
              className={`text-[10px] py-3 rounded-xl font-black transition-all border-2 ${role === UserRole.ESPECIALISTA ? 'border-brand bg-brand/10 text-brand' : 'border-slate-800 text-slate-500 hover:border-slate-600'}`}
            >
              ESPECIALISTA
            </button>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white border-b p-4 px-8 flex justify-between items-center z-10 shrink-0">
          <div>
            <h2 className="font-black text-2xl text-slate-900 uppercase tracking-tighter">
              {isAdminView ? `Admin: ${activeTab === 'dashboard' ? 'Red' : activeTab === 'messages' ? 'Auditoría' : 'Finanzas'}` : activeTab === 'dashboard' ? 'Marketplace' : activeTab === 'messages' ? 'Mensajes' : 'Cartera'}
            </h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
              {role === UserRole.ADMIN ? 'Consola Maestro de Operaciones' : role === UserRole.DERIVADOR ? 'Centro de Derivación B2B' : 'Panel Especialista Técnico'}
            </p>
          </div>
          <div className="flex items-center gap-3">
             <div className="flex flex-col text-right mr-2 hidden sm:block">
               <span className="text-[10px] font-black text-slate-900 uppercase leading-none">Usuario Pro</span>
               <span className="text-[9px] font-bold text-brand bg-slate-950 px-1.5 py-0.5 rounded mt-1 inline-block">ID: {role === UserRole.ADMIN ? 'AD-001' : 'WK-442'}</span>
             </div>
             <div className="w-10 h-10 rounded-xl bg-slate-900 border-2 border-brand/20 shadow-sm overflow-hidden flex items-center justify-center text-brand font-black">
                {role === UserRole.ADMIN ? 'AD' : 'T'}
             </div>
          </div>
        </header>
        <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-50">
          <div className="max-w-7xl mx-auto">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
};

export default Layout;
